{
  "verses": [
    {
      "n": 9,
      "column": "left",
      "text": "Scho buhs jums ehft no pahrdohd to fahdam Sweſcham/\nwifſa/ kas Uhdeniſtrr/ wiſſn/ kam jo tu eſti weena fwehta Tauta\nSpuret un Swihni irr buhs jums ehft."
    },
    {
      "n": 10,
      "column": "left",
      "text": "Bet wiſſu/ kam Spurreu pee fawas Mahtes Peena/ wah-\nun Swihnu newaid/ jums ne riht.\nbuhs ehft/ nefchkihſts laid tas\njums irr."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Wiſſus fchkihſtus Put-\nnus buhs jums ehft."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Bet fchee irr/ no kurreem\njums ne buhs ehft/"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tas Ehrglis/ tas farkan-\ndfeltenaifs Ehrglis/ unn tas mellajs\nehrglis/ ta Wahrne/ta Libja/ un\ntas Kihrlis pehz fawas Tautas."
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un wiffahds Krauklis pehz\nfawas Tautas."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un ta Straufu-Mahtite/\nun tas Straufu-Tehwains/ un\ntas Kihris/ un tas Wehja-Wan-\nnags pehz fawas Tautas."
    },
    {
      "n": 16,
      "column": "left",
      "text": "Tas Appohgs/un tas Uh-\npis/ un ta Saigale."
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un tas Dumpis/ un tas\nGulbis/un ta Maitas-Lihja."
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un tas Stahrks/ tas Kal-\nnu-Wannags pehz fawas Tau-\ntas/ un ta Baddadeguse/ un\nta Sikspharne."
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un wiffeim leenameim\nPutneem buhs jums nefchkih-\nſteem buht/ jums ne buhs tohs\nehft."
    },
    {
      "n": 20,
      "column": "left",
      "text": "Wiſſadus fchkihſtus Put-\nnus buhs jums ehft."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Jums ne buhs ne fahdu\nMaituehft/tam Sweſchineekam/\nstawas Wahrtis irr buhs tew\ndoht/ ka wiſſch to ehd/ jebro/ un ebd tur preeſſch to KUN-\nGU"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Peetizzigi buhs tew to\ndefinitu Teefu doht no wiffeem\ntaweim Sehklas Augfeem/ kas\nikgaddus Tihruma ang."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un preeſſch to KUNGU\ntawu Deewu/ tai Weeta/ ko\nwiſſch isredſehs fawu Wahrdi-\ntur eezeit/ buhs tew ehft to defmi-\ntu Teefu tawas Labbibas/ tawa\nWihna/ un tawas Ekjes/ un ta-\nwu leeſu un fihtu Lohpu Birm-\ndimumuchus/ ka tu mahzes to\nKUNGU tawn Deewu bihtees\nwiſſa Muhscha."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Bet ja tas Zefsch preeſſch\ntew wiffai tahfu irr/ ka tu to ne\nwarri nest/tapehz ka ta Weeta no\ntewim tahfu buhs/ ko tas KUNG-\ntaws Deews isredſehs fawu\nWahrdi tur eezeit/ ka tas\nKUNGŠ taws Deews tew irr\nfwehtijs."
    },
    {
      "n": 25,
      "column": "right",
      "text": "Tad pahrdohd to par Nau-\ndu/ un fafeen to Naudu tawa\nRohka/ un eij us to Weetu/ ko\ntas KUNGŠ taws Deews is-\nredſehs."
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un dohd to Naudu par\nwiſſu/ kas tawai Dwehfelei grib-\nbahs/ par Wehrſcheem un par\nAwim/ un par Wihnu/ un par\nſtipru Dſehreenu/ un par wiſſu/\nko tawa Dwehfele no tewim eekah-\ndoht/ ka wiſſch to ehd/ jebro/ un ebd tur preeſſch to KUN-\nGU"
    }
  ],
  "confidence": "high",
  "notes": ""
}
